Write-Host "Mise a jour App.tsx avec DatabasePage..." -ForegroundColor Yellow

$app = [System.IO.File]::ReadAllText((Join-Path (Get-Location).Path "frontend\src\ui\App.tsx"))
if (-not $app.Contains("DatabasePage")) {
  $app = $app -replace "import \{ SuiviEvalPage \}", "import { SuiviEvalPage } from `"./pages/SuiviEvalPage`";`nimport { DatabasePage } from `"./pages/DatabasePage`""
  $app = $app -replace "<Route path=`"/suivi-eval`"", "<Route path=`"/database`" element={<DatabasePage />} />`n          <Route path=`"/suivi-eval`""
  [System.IO.File]::WriteAllText((Join-Path (Get-Location).Path "frontend\src\ui\App.tsx"), $app, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  App.tsx patche" -ForegroundColor Gray
}


$layout = [System.IO.File]::ReadAllText((Join-Path (Get-Location).Path "frontend\src\ui\Layout.tsx"))
if (-not $layout.Contains("database")) {
  $layout = $layout -replace "to: `"/suivi-eval`"", "to: `"/database`", label: `"Admin PostgreSQL`", tag: `"NEW`" },`n    { to: `"/suivi-eval`""
  [System.IO.File]::WriteAllText((Join-Path (Get-Location).Path "frontend\src\ui\Layout.tsx"), $layout, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  Layout.tsx patche" -ForegroundColor Gray
}


